const { Problem } = require('../models');

async function solve({ includeComponents = false, limit = 50, difficulty, tags } = {}) {
  // Validate inputs
  if (limit <= 0) limit = 50;

  // Build query filters
  const where = {};
  if (difficulty) where.difficulty = difficulty;
  if (tags && tags.length) where.tags = { $overlap: tags };

  // Fetch problems with filters and limit
  let problems = await Problem.findAll({
    where,
    limit,
  });

  // Prepare response
  const response = {
    problems,
    metadata: {},
  };

  if (includeComponents) {
    // Aggregate componentLanguageTotals and componentStatusTotals on filtered+limited problems
    const componentLanguageTotals = {};
    const componentStatusTotals = {};

    for (const problem of problems) {
      if (!problem.components) continue;

      for (const comp of problem.components) {
        // Deduplicate and sort componentLanguages case-insensitively per problem
        if (comp.languages && Array.isArray(comp.languages)) {
          const uniqueLangs = [...new Set(comp.languages.map(l => l.toLowerCase()))];
          uniqueLangs.forEach(lang => {
            componentLanguageTotals[lang] = (componentLanguageTotals[lang] || 0) + 1;
          });
        }
        if (comp.status) {
          const status = comp.status.toLowerCase();
          componentStatusTotals[status] = (componentStatusTotals[status] || 0) + 1;
        }
      }
    }

    response.metadata.componentLanguageTotals = componentLanguageTotals;
    response.metadata.componentStatusTotals = componentStatusTotals;
  }

  return response;
}

module.exports = { solve };
